scwin.validateCommon = async function (payload) {
    let comp = PASSWD
    if (payload.BULK_YN === "0" && payload.CNTR_YN === "0") {
        await $c.win.alert("화물 구분은 최소 하나 이상 선택해 주세요.");
        comp = scwin.compMapping.BULK_YN;
        comp.focus();
        return false;
    }

    if (payload.PASSWD.length < 4 || payload.PASSWD.length > 10) {
        await $c.win.alert("비밀번호는 4~10자로 입력해 주세요.");
        comp = scwin.compMapping.PASSWD;
        comp.focus();
        return false;
    }

    if (payload.PASSWD !== PASSWD_CHK.getValue()) {
        await $c.win.alert("비밀번호와 비밀번호 확인이 일치하지 않습니다.");
        comp = scwin.compMapping.PASSWD;
        comp.focus();
        return false;
    }
    if (! await scwin.requireValue(payload.MBR_NM, "배차담당자 성명을 입력해 주세요.", scwin.compMapping.MBR_NM)
        || ! await scwin.requireValue(payload.MP_NO, "휴대전화를 입력해 주세요.", scwin.compMapping.MP_NO)
        || ! await scwin.requireValue(payload.TEL_NO, "전화번호를 입력해 주세요.", scwin.compMapping.TEL_NO)
        || ! await scwin.isValidEmail(payload.EMAIL, "이메일 형식을 확인해 주세요", scwin.compMapping.EMAIL)
        || ! await scwin.requireValue(payload.LOBRAN_CD, "신청점소를 선택해 주세요.", scwin.compMapping.LOBRAN_CD)
        || ! await scwin.requireValue(payload.BUSI_CLS_CD, "사업자구분을 선택해 주세요.", scwin.compMapping.BUSI_CLS_CD)
        || ! await scwin.requireValue(payload.BUSI_NM, "회사명을 입력해 주세요.", scwin.compMapping.BUSI_NM)
        || ! await scwin.requireValue(payload.CRN, "사업자등록번호를 입력해 주세요.", scwin.compMapping.CRN)
        || ! await scwin.requireValue(payload.REPST_NM, "대표자 성명을 입력해 주세요.", scwin.compMapping.REPST_NM)
        || ! await scwin.requireValue(payload.BUSI_ZIP, "사업장 주소를 입력해 주세요.", scwin.compMapping.BUSI_ZIP)
        || ! await scwin.requireValue(payload.BUSI_ADDR_1, "사업장 주소를 입력해 주세요.", scwin.compMapping.BUSI_ADDR_1)
        || ! await scwin.requireValue(payload.MAIL_ZIP, "우편물 수령지를 입력해 주세요.", scwin.compMapping.MAIL_ZIP)
        || ! await scwin.requireValue(payload.MAIL_ADDR_1, "우편물 수령지를 입력해 주세요.", scwin.compMapping.MAIL_ADDR_1)) {
        return false;
    }

/*     if (!scwin.isValidEmail(payload.EMAIL)) {
        $c.win.alert("이메일 형식을 확인해 주세요.");
        return false;
    } */

    return true;
};

scwin.validateBroker = async function (payload) {
    var row = 0;
    var validVehicleRowCount = 0;

    if (payload.TRANS_BIZ_YN === "0" && payload.INTCD_BIZ_YN === "0") {
        await $c.win.alert("사업구분은 최소 하나 이상 선택해 주세요.");
        comp = scwin.compMapping.TRANS_BIZ_YN;
        comp.focus();
        return false;
    }

    for (row = 1; row <= 5; row += 1) {
        var kind = payload["VEHCL_KIND_CD" + row];
        var norm = payload["VEHCL_NRM_CD" + row];
        var count = payload["VEHCL_CNT" + row];
        var rowValues = [kind, norm, count];

        if (!scwin.hasAnyValue(rowValues)) {
            continue;
        }
		debugger;
        if (!scwin.isBlank(kind) && !scwin.isBlank(norm) && !scwin.isBlank(count)) {
            validVehicleRowCount += 1;
        }
    }

    if (validVehicleRowCount === 0) {
        await $c.win.alert("보유차량은 최소 하나 이상 입력해 주세요.");
        return false;
    }

    if (!await scwin.requireValue(payload.PREF_KCG_CD_1, "선호 화종은 최소 하나 이상 입력하셔야됩니다.", scwin.compMapping.PREF_KCG_CD_1)
        || !await scwin.requireValue(payload.MAIN_DST1_DPT, "선호구간은 필수 입력하셔야됩니다.", scwin.compMapping.MAIN_DST1_DPT)
        || !await scwin.requireValue(payload.MAIN_DST1_ARV, "선호구간은 필수 입력하셔야됩니다.", scwin.compMapping.MAIN_DST1_ARV)) {
        return false;
    }

    return true;
};

scwin.validateDriver = async function (payload) {
    var hasDate = !scwin.isBlank(payload.BOND_TRANS_LCNS_ST_DT) || !scwin.isBlank(payload.BOND_TRANS_LCNS_END_DT);

    if (!await scwin.requireValue(payload.VEHCL_NO, "차량번호를 입력해 주세요.", scwin.compMapping.VEHCL_NO)
        || !await scwin.requireValue(payload.VEHCL_KND_CD, "차량종류를 선택해 주세요.", scwin.compMapping.VEHCL_KND_CD)
        || !await scwin.requireValue(payload.MAIN_DST1_DPT, "선호구간은 필수 입력하셔야됩니다.", scwin.compMapping.MAIN_DST1_DPT)
        || !await scwin.requireValue(payload.MAIN_DST1_ARV, "선호구간은 필수 입력하셔야됩니다.", scwin.compMapping.MAIN_DST1_ARV)) {
        return false;
    }

    if (hasDate && (scwin.isBlank(payload.BOND_TRANS_LCNS_ST_DT) || scwin.isBlank(payload.BOND_TRANS_LCNS_END_DT))) {
        await $c.win.alert("보세운송면허기간은 시작일과 종료일을 모두 입력해 주세요.");
        comp = scwin.compMapping.BOND_TRANS_LCNS_ST_DT;
        comp.focus();
        return false;
    }

    if (!scwin.compareDateRange(payload.BOND_TRANS_LCNS_ST_DT, payload.BOND_TRANS_LCNS_END_DT)) {
        await $c.win.alert("시작일자는 종료일자 이전이어야 합니다.");
        comp = scwin.compMapping.BOND_TRANS_LCNS_END_DT;
        comp.focus();
        return false;
    }

    return true;
};

