scwin.loadForm = async function () {
    var response = null;
    var member = null;

    try {
        response = await scwin.requestJson("/MemberControl", {
            cmd: "mformJson"
        });
    } catch (error) {
        scwin.showError("회원정보 조회 중 오류가 발생했습니다.");
        return;
    }

    if (!response.success) {
        $c.win.alert(response.message || "");
        await scwin.moveFrame("/ui/member/index_main.xml");
        return;
    }
    member = response.member || {};
    scwin.state.mbrClsCd = scwin.safe(member.MBR_CLS_CD);
    scwin.state.memberId = scwin.safe(member.MBR_ID);

    scwin.applySectionVisibility();
    scwin.applyStaticCombo(response.combo || {});
    scwin.applyCommonData(member, response.combo || {});

    if (scwin.state.mbrClsCd === "04") {
        await scwin.applyBrokerData(member);
        temp1.setInitDate("", "");
        return;
    }

    if (scwin.state.mbrClsCd === "05") {
        await scwin.applyDriverData(member);
        return;
    }
    checkbox2.setValue("0");
    temp1.setInitDate("", "");
};

scwin.save = async function () {
    scwin.onUdcCompleted();
    var payload = scwin.collectPayload();
    var response = null;

    if (!await scwin.validateCommon(payload)) {
        return;
    }

    if (scwin.state.mbrClsCd === "04" && ! await scwin.validateBroker(payload)) {
        return;
    }

    if (scwin.state.mbrClsCd === "05" && ! await scwin.validateDriver(payload)) {
        return;
    }

    try {
        response = await scwin.requestJson("/MemberControl", Object.assign({ cmd: "modifyJson" }, payload), "POST");
    } catch (error) {
        scwin.showError("회원정보 수정 중 오류가 발생했습니다.");
        return;
    }

    $c.win.alert(response.message || "");

    if (response.success) {
        await scwin.loadForm();
    }
};

scwin.resetForm = async function () {
    await scwin.loadForm();
};

scwin.closePage = async function () {
    await scwin.moveFrame("/ui/member/index_main.xml");
};

scwin.onpageload = async function () {
    //로드시 다른 데이터가 왜 들어가는지 확인이 안됨. 초기화 필요
    $c.gus.cfInitObjects(table1, null);
    $c.gus.cfInitObjects(table2, null);
    $c.gus.cfInitObjects(table3, null);
    $c.gus.cfInitObjects(table4, null);
    PASSWD.setValue("");
    PASSWD_CHK.setValue("");
    checkbox2.setValue("0");
    grp_broker_detail.hide();
    grp_driver_detail.hide();
    await scwin.loadForm();
};

scwin.f_onlyNum = async function (info) {
    await $c.win.alert("숫자만 입력이 가능합니다.");
    let comp = $p.getComponentById(info.callerId);
    comp.focus();
};
